+				claimUID:      1,
+				otherClaimUID: 10,
+			},
+			claimUID:       claimUID,
+			allocatedClaim: allocatedClaim,
+			expectedInFlightAllocationSharers: map[types.UID]int{
+				claimUID:      2,
+				otherClaimUID: 10,
+			},
+		},
+	}
